import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It uses Go's os/exec package to construct the pipeline safely without relying on the shell.
// Returns the stdout of the command pipeline (the formatted JSON) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Construct the aliyun command
	// Using argument slices prevents shell injection
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Construct the jq command
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the stdout of aliyun to the stdin of jq
	pipeReader, pipeWriter := io.Pipe()
	cmdAliyun.Stdout = pipeWriter
	cmdJq.Stdin = pipeReader

	// Create the output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// We want to capture the output to return it as a string, as well as write it to the file
	var outBuf bytes.Buffer
	multiWriter := io.MultiWriter(&outBuf, file)
	cmdJq.Stdout = multiWriter

	// Capture stderr from both commands to provide context in case of errors
	var errBuf bytes.Buffer
	cmdAliyun.Stderr = &errBuf
	cmdJq.Stderr = &errBuf

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, errBuf.String())
	}

	// Start the jq command
	if err := cmdJq.Start(); err != nil {
		// If jq fails to start, kill the aliyun process
		_ = cmdAliyun.Process.Kill()
		_ = pipeWriter.Close()
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, errBuf.String())
	}

	// Wait for aliyun to finish
	if err := cmdAliyun.Wait(); err != nil {
		// If aliyun fails, kill jq and close the pipe
		_ = cmdJq.Process.Kill()
		_ = pipeWriter.Close()
		return "", fmt.Errorf("aliyun command execution failed: %w, stderr: %s", err, errBuf.String())
	}

	// Close the write end of the pipe to signal EOF to jq
	// This is important because cmdAliyun.Wait() might not close the pipe immediately in all scenarios
	_ = pipeWriter.Close()

	// Wait for jq to finish
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command execution failed: %w, stderr: %s", err, errBuf.String())
	}

	return outBuf.String(), nil
}

