package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI to describe SLBs, pipes the output to jq for formatting,
// saves the result to the specified output file, and returns the formatted string.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Step 1: Create the command for querying aliyun SLB
	// Command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Step 2: Create the command for jq formatting
	// Command: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Step 3: Setup the pipe between aliyun and jq
	// aliyun's stdout -> jq's stdin
	pipeReader, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %v", err)
	}
	cmdJq.Stdin = pipeReader

	// Step 4: Setup the output for jq
	// We want to write to a file AND return the string, so we use a MultiWriter.
	var outputBuffer bytes.Buffer

	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %v", outputFile, err)
	}
	defer file.Close()

	// Write to both the buffer (for return value) and the file
	multiWriter := io.MultiWriter(&outputBuffer, file)
	cmdJq.Stdout = multiWriter

	// Step 5: Start the commands
	// Start aliyun first
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %v", err)
	}

	// Start jq (it will wait for input from the pipe)
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %v", err)
	}

	// Step 6: Wait for commands to finish
	// Wait for aliyun to finish producing data
	if err := cmdAliyun.Wait(); err != nil {
		// If aliyun fails, the pipe breaks, but we should wait for jq to finish processing whatever it got or error out
		return "", fmt.Errorf("aliyun command execution failed: %v", err)
	}

	// Wait for jq to finish processing
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command execution failed: %v", err)
	}

	return outputBuffer.String(), nil
}

func main() {
	// Example usage
	// Note: This requires 'aliyun' CLI tool and 'jq' to be installed and available in the system PATH.
	name := "my-load-balancer"
	outFile := "output.json"

	result, err := QuerySLBAndExport(name, outFile)
	if err != nil {
		fmt.Printf("Error executing query: %s\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully queried SLB '%s' and exported to '%s'.\n", name, outFile)
	fmt.Println("--- Result Content ---")
	fmt.Println(result)
}

