// It returns the formatted output string and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Define the aliyun command
	// Command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Define the jq command
	// Command: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the stdout of aliyun to the stdin of jq
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Create a buffer to capture the output from jq
	var outBuf bytes.Buffer
	cmdJq.Stdout = &outBuf

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Run the jq command (which reads from the pipe)
	// Run() waits for the command to finish
	if err := cmdJq.Run(); err != nil {
		return "", fmt.Errorf("failed to run jq command: %w", err)
	}

	// Wait for the aliyun command to finish completely
	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command finished with error: %w", err)
	}

	// Write the captured output to the specified file
	// This corresponds to the "> output.json" part of the shell command
	if err := os.WriteFile(outputFile, outBuf.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write to output file %s: %w", outputFile, err)
	}

	return outBuf.String(), nil
}

