package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It uses a safe pipeline implementation without invoking a shell.
// Returns the combined stderr of the pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("input parameters cannot be empty")
	}

	// Create the aliyun command
	// Using separate arguments prevents shell injection
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun stdout to jq stdin
	pipeReader, pipeWriter := io.Pipe()
	aliyunCmd.Stdout = pipeWriter
	jqCmd.Stdin = pipeReader

	// Open the output file for writing
	file, err := os.OpenFile(outputFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to open output file: %w", err)
	}
	defer file.Close()

	// Redirect jq stdout to the file
	jqCmd.Stdout = file

	// Capture stderr from both commands to return as the result string
	// Since stdout is redirected to the file, the returned string will contain logs/errors
	var errBuffer bytes.Buffer
	aliyunCmd.Stderr = &errBuffer
	jqCmd.Stderr = &errBuffer

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return errBuffer.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		// If jq fails to start, kill aliyun to prevent leaks
		_ = aliyunCmd.Process.Kill()
		_ = aliyunCmd.Wait()
		return errBuffer.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish in a separate goroutine to close the pipe writer
