import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It avoids shell injection by executing commands directly without an intervening shell.
// Returns the stderr of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation
	if loadBalancerName == "" || outputFile == "" {
		return "", fmt.Errorf("input parameters cannot be empty")
	}

	// Setup the aliyun command.
	// Arguments are passed as a separate list to exec.Command, which prevents shell injection.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Setup the jq command.
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin.
	pipeReader, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %w", err)
	}
	cmdJq.Stdin = pipeReader

	// Setup the output file for jq's stdout.
	// This replaces the shell redirection (>).
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()
	cmdJq.Stdout = file

	// Capture stderr from both commands to return in the result string.
	// This mimics the behavior of CombinedOutput for debugging purposes.
	var stderrBuf bytes.Buffer
	cmdAliyun.Stderr = &stderrBuf
	cmdJq.Stderr = &stderrBuf

	// Start the aliyun command.
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w, stderr: %s", err, stderrBuf.String())
	}

	// Start the jq command.
	if err := cmdJq.Start(); err != nil {
		// Attempt to kill the aliyun process if jq fails to start to avoid orphan processes.
		_ = cmdAliyun.Process.Kill()
		return "", fmt.Errorf("failed to start jq command: %w, stderr: %s", err, stderrBuf.String())
	}

	// Wait for aliyun to finish.
	// Since aliyun is writing to the pipe, we wait for it to complete.
	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command execution failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Wait for jq to finish processing.
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command execution failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Return the captured stderr content (logs/errors).
	return stderrBuf.String(), nil
}

