package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI to describe SLBs, pipes the output to jq for formatting,
// and saves the result to the specified output file.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the command for aliyun CLI
	// Arguments are passed as a slice to avoid shell injection
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the command for jq
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the stdout of aliyun to the stdin of jq
	pr, pw := io.Pipe()
	aliyunCmd.Stdout = pw
	jqCmd.Stdin = pr

	// Create a buffer to capture the output from jq
	var outBuf bytes.Buffer
	jqCmd.Stdout = &outBuf

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		pw.Close()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish
	// We must wait for aliyun to finish before closing the write end of the pipe,
	// otherwise jq might get an EOF prematurely.
	if err := aliyunCmd.Wait(); err != nil {
		pw.Close()
		return "", fmt.Errorf("aliyun command execution failed: %w", err)
	}

	// Close the write end of the pipe so jq knows the input is finished
	pw.Close()

	// Wait for jq to finish
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command execution failed: %w", err)
	}

	// Write the formatted output to the specified file
	if err := os.WriteFile(outputFile, outBuf.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file %s: %w", outputFile, err)
	}

	return outBuf.String(), nil
}

func main() {
	// Example usage
	name := "my-load-balancer"
	file := "output.json"

	result, err := QuerySLBAndExport(name, file)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully queried SLB and exported to %s\n", file)
	fmt.Printf("Result preview:\n%s\n", result)
}

