func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Construct the command pipeline.
	// We use 'sh -c' to handle the pipe (|) between aliyun and jq.
	// We do not include the shell redirection ('>') here so that we can capture
	// the output in Go to return it, then write it to the file manually.
