	// Run the command and capture combined output (stdout + stderr)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return string(output), fmt.Errorf("failed to execute command: %w", err)
	}

	// Write the captured output to the specified file
	// 0644 permissions: owner read/write, group/others read
	if err := os.WriteFile(outputFile, output, 0644); err != nil {
		return string(output), fmt.Errorf("failed to write to output file %s: %w", outputFile, err)
	}

	return string(output), nil
}

