package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq using Go pipelines, and saves it to the specified file.
// Returns the stdout of the pipeline (the formatted JSON) and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Construct the aliyun command.
	// Using exec.Command directly with arguments avoids shell injection vulnerabilities
	// associated with sh -c.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Construct the jq command.
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Create a pipe to connect the stdout of aliyun to the stdin of jq.
	pipeReader, pipeWriter := io.Pipe()
	cmdAliyun.Stdout = pipeWriter
	cmdJq.Stdin = pipeReader

	// 4. Setup output handling.
	// We want to write the output to the specified file AND capture it in memory to return.
	var outputBuffer bytes.Buffer
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// MultiWriter allows writing to both the file and the buffer simultaneously.
	cmdJq.Stdout = io.MultiWriter(file, &outputBuffer)

	// 5. Start the commands.
	// We start jq first so it is ready to read from the pipe as soon as aliyun writes.
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// 6. Wait for commands to finish.
	// Wait for aliyun to finish. When it exits, pipeWriter will be closed, sending EOF to jq.
	if err := cmdAliyun.Wait(); err != nil {
		// Attempt to wait for jq to finish to avoid zombie processes, though it might fail on broken pipe.
		_ = cmdJq.Wait()
		return outputBuffer.String(), fmt.Errorf("aliyun command execution failed: %w", err)
	}

	// Explicitly close the pipe writer to ensure jq receives EOF if aliyun.Wait() didn't trigger it.
	pipeWriter.Close()

	// Wait for jq to finish processing.
	if err := cmdJq.Wait(); err != nil {
		return outputBuffer.String(), fmt.Errorf("jq command execution failed: %w", err)
	}

	return outputBuffer.String(), nil
}

func main() {
