	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Run the aliyun command
	if err := cmdAliyun.Run(); err != nil {
		pw.Close()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close the write end of the pipe to signal EOF to jq
	pw.Close()

	// Wait for jq to finish processing
