package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// It uses os/exec to construct a safe pipeline without relying on the shell.
// Returns the processed JSON content and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the output file
	f, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer f.Close()

	// Command 1: aliyun CLI
	// Using exec.Command with arguments directly prevents shell injection.
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Command 2: jq
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect stdout of aliyun to stdin of jq
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Use a MultiWriter to write to both the file and a buffer.
	// This allows us to satisfy the requirement of exporting to a file
	// while also returning the string result to the caller.
	var buf bytes.Buffer
	cmdJq.Stdout = io.MultiWriter(f, &buf)

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish
	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command execution failed: %w", err)
	}

	// Wait for jq to finish
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command execution failed: %w", err)
	}

	return buf.String(), nil
}

