package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun slb DescribeLoadBalancers command,
// pipes the output to jq for formatting, saves the result to a file,
// and returns the formatted string.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Define the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Define the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipeReader, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %w", err)
	}
	jqCmd.Stdin = pipeReader

	// Prepare the output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Use a buffer to capture the output for the return value
	var outputBuffer bytes.Buffer

	// Use MultiWriter to write to both the buffer (for return) and the file (for export)
	jqCmd.Stdout = io.MultiWriter(&outputBuffer, file)

	// Capture stderr from both commands to include in error messages
	var stderrBuffer bytes.Buffer
	aliyunCmd.Stderr = &stderrBuffer
	jqCmd.Stderr = &stderrBuffer

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		// If jq fails, attempt to kill the aliyun process to avoid leaks
		_ = aliyunCmd.Process.Kill()
		_ = aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for jq to finish processing the input
	// We wait for the consumer (jq) first to ensure the pipe is fully read.
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq execution failed: %w, stderr: %s", err, stderrBuffer.String())
	}

	// Wait for aliyun to finish producing output
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun execution failed: %w, stderr: %s", err, stderrBuffer.String())
	}

	return outputBuffer.String(), nil
}

func main() {
	// Example usage
	// Note: This requires 'aliyun' and 'jq' to be installed and configured in the system PATH.
	name := "my-slb-name"
	outFile := "output.json"

	result, err := QuerySLBAndExport(name, outFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully queried and exported SLB info to %s\n", outFile)
	fmt.Printf("Result:\n%s\n", result)
}

